// Violation: adding a new payment type requires editing existing class
class PaymentProcessor {
    public void process(Payment p) {
        if (p.type == CREDIT_CARD) { chargeCard(p); }
        else if (p.type == PAYPAL)  { chargePaypal(p); } // edit every time
        else if (p.type == CRYPTO)  { chargeCrypto(p); } // keeps growing
    }
}

// OCP via Strategy — closed for modification, open for extension
interface PaymentStrategy {
    void charge(Payment payment);
}

class CreditCardStrategy implements PaymentStrategy {
    public void charge(Payment p) { chargeCard(p); }
}

class CryptoStrategy implements PaymentStrategy {
    public void charge(Payment p) { chargeCrypto(p); }
}

class PaymentProcessor {
    private final PaymentStrategy strategy;
    // Add new payment type: implement PaymentStrategy, inject it. Done.
    public void process(Payment p) { strategy.charge(p); }
}

// Classic LSP violation: Rectangle / Square
class Rectangle {
    int width, height;
    void setWidth(int w)  { this.width = w; }
    void setHeight(int h) { this.height = h; }
    int area() { return width * height; }
}

class Square extends Rectangle {
    @Override void setWidth(int w)  { width = height = w; } // breaks contract!
    @Override void setHeight(int h) { width = height = h; }
}

// This breaks with a Square:
void resize(Rectangle r) {
    r.setWidth(5); r.setHeight(3);
    assert r.area() == 15; // FAILS for Square — area is 9
}

// Fix: don't inherit when the subtype can't honour the supertype's contract
interface Shape { int area(); }
record ImmutableRectangle(int width, int height) implements Shape {
    public int area() { return width * height; }
}
record ImmutableSquare(int side) implements Shape {
    public int area() { return side * side; }
}

// Fat interface — ISP violation
interface Worker {
    void work();
    void eat();   // robots don't eat!
    void sleep();  // robots don't sleep!
}

class Robot implements Worker {
    public void work() { /* real impl */ }
    public void eat()  { throw new UnsupportedOperationException(); } // forced stub
    public void sleep(){ throw new UnsupportedOperationException(); }
}

