    public void work() { /* ... */ } // only what it needs
}

// Violation: high-level OrderService depends on low-level MySQLOrderRepo
class OrderService {
    private MySQLOrderRepository repo = new MySQLOrderRepository(); // hard dependency
    public void place(Order o) { repo.save(o); }
}

// DIP: both depend on the abstraction
interface OrderRepository {    // abstraction — owned by the domain layer
    void save(Order order);
    Optional<Order> findById(long id);
}

class OrderService {           // high-level module
    private final OrderRepository repo; // depends on interface
    public OrderService(OrderRepository repo) { this.repo = repo; } // injected
    public void place(Order o) { repo.save(o); }
}

class MySQLOrderRepository implements OrderRepository { /* low-level detail */ }
class InMemoryOrderRepository implements OrderRepository { /* for tests */ }

